    while (true) {
        // get length
        int ch;
        int len = 0;
        int read = 0;
        while ((ch = br.read()) != -1) {
            read++;
            if (ch == ' ') {
                // End of length string
                // Get keyword
                StringBuffer sb = new StringBuffer();
                while ((ch = br.read()) != -1) {
                    read++;
                    if (ch == '=') {
                        // end of keyword
                        String keyword = sb.toString();
                        // Get rest of entry
                        char[] cbuf = new char[len - read];
                        int got = br.read(cbuf);
                        if (got != len - read) {
                            throw new IOException("Failed to read Paxheader. Expected " + (len - read) + " chars, read " + got);
                        }
                        // Drop trailing NL
                        String value = new String(cbuf, 0, len - read - 1);
                        headers.put(keyword, value);
                        break;
                    }
                    sb.append((char) ch);
                }
                // Processed single header
                break;
            }
            len *= 10;
            len += ch - '0';
