         * uid,uname
         */
    Iterator hdrs = headers.entrySet().iterator();
    while (hdrs.hasNext()) {
        Entry ent = (Entry) hdrs.next();
        String key = (String) ent.getKey();
        String val = (String) ent.getValue();
